using System;using System.Collections.Generic;using ICSharpCode.WpfDesign;namespace BgCommon.UI.Designer.VersionControl{    /// <summary>    /// 版本记录    /// </summary>    public class VersionRecord    {        /// <summary>        /// 版本ID        /// </summary>        public string Id { get; set; }                /// <summary>        /// 版本描述        /// </summary>        public string Description { get; set; }                /// <summary>        /// 创建时间        /// </summary>        public DateTime CreatedAt { get; set; }                /// <summary>        /// 设计内容        /// </summary>        public string Content { get; set; }    }        /// <summary>    /// 版本控制管理器    /// </summary>    public class VersionControlManager    {        private readonly DesignContext _context;        private readonly List<VersionRecord> _versionHistory = new List<VersionRecord>();        private int _currentVersionIndex = -1;        private const int MaxHistorySize = 50;                /// <summary>        /// 版本历史记录        /// </summary>        public IReadOnlyList<VersionRecord> VersionHistory => _versionHistory.AsReadOnly();                /// <summary>        /// 当前版本索引        /// </summary>        public int CurrentVersionIndex => _currentVersionIndex;                /// <summary>        /// 是否可以撤销        /// </summary>        public bool CanUndo => _currentVersionIndex > 0;                /// <summary>        /// 是否可以重做        /// </summary>        public bool CanRedo => _currentVersionIndex < _versionHistory.Count - 1;                /// <summary>        /// 构造函数        /// </summary>        /// <param name="context">设计上下文</param>        public VersionControlManager(DesignContext context)        {            _context = context;        }                /// <summary>        /// 创建版本        /// </summary>        /// <param name="description">版本描述</param>        public void CreateVersion(string description)        {            // 移除当前版本之后的所有版本            if (_currentVersionIndex < _versionHistory.Count - 1)            {                _versionHistory.RemoveRange(_currentVersionIndex + 1, _versionHistory.Count - _currentVersionIndex - 1);            }                        // 保存当前设计内容            var content = SaveDesignContent();            var version = new VersionRecord            {                Id = Guid.NewGuid().ToString(),                Description = description,                CreatedAt = DateTime.Now,                Content = content            };                        _versionHistory.Add(version);            _currentVersionIndex++;                        // 限制历史记录大小            if (_versionHistory.Count > MaxHistorySize)            {                _versionHistory.RemoveAt(0);                _currentVersionIndex--;            }        }                /// <summary>        /// 撤销        /// </summary>        public void Undo()        {            if (CanUndo)            {                _currentVersionIndex--;                LoadVersion(_currentVersionIndex);            }        }                /// <summary>        /// 重做        /// </summary>        public void Redo()        {            if (CanRedo)            {                _currentVersionIndex++;                LoadVersion(_currentVersionIndex);            }        }                /// <summary>        /// 加载版本        /// </summary>        /// <param name="index">版本索引</param>        private void LoadVersion(int index)        {            if (index >= 0 && index < _versionHistory.Count)            {                var version = _versionHistory[index];                LoadDesignContent(version.Content);            }        }                /// <summary>        /// 保存设计内容        /// </summary>        /// <returns>设计内容</returns>        private string SaveDesignContent()        {            using (var stringWriter = new System.IO.StringWriter())            using (var xmlWriter = System.Xml.XmlWriter.Create(stringWriter, new System.Xml.XmlWriterSettings { Indent = true }))            {                _context.Save(xmlWriter);                return stringWriter.ToString();            }        }                /// <summary>        /// 加载设计内容        /// </summary>        /// <param name="content">设计内容</param>        private void LoadDesignContent(string content)        {            using (var stringReader = new System.IO.StringReader(content))            using (var xmlReader = System.Xml.XmlReader.Create(stringReader))            {                var loadSettings = new ICSharpCode.WpfDesign.Designer.Xaml.XamlLoadSettings();                var tempContext = new ICSharpCode.WpfDesign.Designer.Xaml.XamlDesignContext(xmlReader, loadSettings);                                // 复制内容到当前设计上下文                if (tempContext.RootItem != null)                {                    // 清除当前内容                    _context.RootItem.CollectionElements.Clear();                                        // 添加新内容                    foreach (var child in tempContext.RootItem.CollectionElements)                    {                        _context.RootItem.CollectionElements.Add(child);                    }                }            }        }                /// <summary>        /// 比较两个版本        /// </summary>        /// <param name="version1">版本1</param>        /// <param name="version2">版本2</param>        /// <returns>差异</returns>        public string CompareVersions(VersionRecord version1, VersionRecord version2)        {            // 这里可以实现版本比较逻辑            // 例如，使用文本差异算法比较两个版本的内容            return "差异比较结果";        }                /// <summary>        /// 导出版本历史        /// </summary>        /// <param name="path">导出路径</param>        public void ExportHistory(string path)        {            // 这里可以实现版本历史导出逻辑        }                /// <summary>        /// 导入版本历史        /// </summary>        /// <param name="path">导入路径</param>        public void ImportHistory(string path)        {            // 这里可以实现版本历史导入逻辑        }    }}